import { db } from "@/db";
import { customers } from "@/db/schema";
import { SQL, and, asc, eq, gt, ilike, or, sql } from "drizzle-orm";
import { NextRequest, NextResponse } from "next/server";

const PAGE_SIZE = 20;

interface CustomerCursor {
    name: string;
    id: string;
}

function encodeCursor(cursor: CustomerCursor) {
    return Buffer.from(JSON.stringify(cursor)).toString("base64url");
}

function decodeCursor(cursor: string | null): CustomerCursor | null {
    if (!cursor) return null;

    try {
        const parsed = JSON.parse(Buffer.from(cursor, "base64url").toString("utf8"));
        if (
            parsed &&
            typeof parsed.name === "string" &&
            typeof parsed.id === "string"
        ) {
            return parsed;
        }
    } catch {
        return null;
    }

    return null;
}

export async function GET(req: NextRequest) {
    const { searchParams } = new URL(req.url);
    const query = searchParams.get("q")?.trim() ?? "";
    const cursor = decodeCursor(searchParams.get("cursor"));
    const outstandingOnly = searchParams.get("outstanding") === "true";

    try {
        const filterConditions: SQL[] = [eq(customers.isActive, true)];

        if (query) {
            const searchPattern = `%${query}%`;
            const searchCondition = or(
                ilike(customers.name, searchPattern),
                ilike(customers.phone, searchPattern),
                ilike(customers.cnic, searchPattern)
            );
            if (searchCondition) {
                filterConditions.push(searchCondition);
            }
        }

        if (outstandingOnly) {
            filterConditions.push(gt(customers.outstandingAmount, "0"));
        }

        const filterWhere = and(...filterConditions);
        const pageConditions = [...filterConditions];

        if (cursor) {
            const cursorName = cursor.name.toLowerCase();
            const cursorCondition = or(
                sql`lower(${customers.name}) > ${cursorName}`,
                and(
                    sql`lower(${customers.name}) = ${cursorName}`,
                    gt(customers.id, cursor.id)
                )
            );
            if (cursorCondition) {
                pageConditions.push(cursorCondition);
            }
        }

        const pageWhere = and(...pageConditions);

        const [{ count }] = await db
            .select({ count: sql<number>`count(*)::int` })
            .from(customers)
            .where(filterWhere);

        const rows = await db
            .select()
            .from(customers)
            .where(pageWhere)
            .orderBy(asc(sql`lower(${customers.name})`), asc(customers.id))
            .limit(PAGE_SIZE + 1);

        const data = rows.slice(0, PAGE_SIZE);
        const lastCustomer = data[data.length - 1];
        const nextCursor = rows.length > PAGE_SIZE && lastCustomer
            ? encodeCursor({ name: lastCustomer.name, id: lastCustomer.id })
            : null;

        return NextResponse.json({
            data,
            nextCursor,
            totalCount: count,
        });
    } catch (error) {
        console.error("Customers API Error:", error);
        return NextResponse.json({ error: "Failed to fetch customers" }, { status: 500 });
    }
}

