}

interface CustomersPage {
    customers: Customer[];
    nextCursor: string | null;
    totalCount: number;
}

interface FetchCustomersOptions {
    search: string;
    outstandingOnly: boolean;
    cursor?: string | null;
}

function parseAmount(value: string | number | null | undefined) {
    if (typeof value === "number") return value;
    if (typeof value === "string") return parseFloat(value || "0");
    return 0;
}

function mapApiCustomer(customer: CustomerApiRecord): Customer {
    return {
        id: customer.id,
        name: customer.name,
        phone: customer.phone,
        cnic: customer.cnic,
        address: customer.address || null,
        outstandingAmount: parseAmount(customer.outstandingAmount),
        paidAmount: parseAmount(customer.paidAmount),
        isActive: customer.isActive,
    };
}

// Server fetcher
async function fetchCustomersFromServer({
    search,
    outstandingOnly,
    cursor,
}: FetchCustomersOptions): Promise<CustomersPage> {
    const params = new URLSearchParams();
    const trimmedSearch = search.trim();

    if (trimmedSearch) params.set("q", trimmedSearch);
    if (cursor) params.set("cursor", cursor);
    if (outstandingOnly) params.set("outstanding", "true");
    params.set("_t", Date.now().toString());

    const res = await fetch(`/api/customers?${params.toString()}`, { cache: "no-store" });
    if (!res.ok) throw new Error('Failed to fetch customers');
    const data = (await res.json()) as CustomersPageResponse;

    return {
        customers: (data.data || []).map(mapApiCustomer),
        nextCursor: data.nextCursor,
        totalCount: data.totalCount,
    };
}

// Offline fetcher
async function fetchCustomersOffline(
    search: string,
    outstandingOnly: boolean
): Promise<CustomersPage> {
    const searchLower = search.trim().toLowerCase();
    const offlineCustomers = await getAllActiveCustomers();
    let customerList = offlineCustomers.map(c => ({
        id: c.id,
        name: c.name,
        phone: c.phone,
        cnic: c.cnic,
        address: c.address || null,
        outstandingAmount: c.outstandingAmount,
        paidAmount: c.paidAmount,
        isActive: c.isActive,
    }));

    if (searchLower) {
        customerList = customerList.filter(customer =>
            customer.name.toLowerCase().includes(searchLower) ||
            customer.phone.toLowerCase().includes(searchLower) ||
            (customer.cnic?.toLowerCase().includes(searchLower) ?? false)
        );
    }

    if (outstandingOnly) {
        customerList = customerList.filter(customer => customer.outstandingAmount > 0);
    }

    customerList.sort((a, b) =>
        a.name.localeCompare(b.name, undefined, { sensitivity: "base" }) ||
        a.id.localeCompare(b.id)
    );

    return {
        customers: customerList,
        nextCursor: null,
        totalCount: customerList.length,
    };
}

